    public Object parseTrade(Object trade, Object... optionalArgs)
    {
        //
        // fetchTrades (public)
        //
        //     {
        //         "id":"c152f814-8eeb-44f0-8f3f-e5c568f2ffcf",
        //         "isMakerBuyer":false,
        //         "baseCurrency":"620f2019-33c0-423b-8a9d-cde4d7f8ef7f",
        //         "quoteCurrency":"0c3a106d-bde3-4c13-a26e-3fd2394529e5",
        //         "price":"4435.56",
        //         "quantity":"0.32534",
        //         "cost":"1443.0650904",
        //         "timestamp":1635854642725,
        //         "makerBuyer":false
        //     }
        //
        // fetchMyTrades (private)
        //
        //     {
        //         "id":"02e02533-b4bf-4ba9-9271-24e2108dfbf7",
        //         "isMakerBuyer":false,
        //         "direction":"TRADE_DIRECTION_BUY",
        //         "baseCurrency":"620f2019-33c0-423b-8a9d-cde4d7f8ef7f",
        //         "quoteCurrency":"0c3a106d-bde3-4c13-a26e-3fd2394529e5",
        //         "price":"4564.32",
        //         "quantity":"0.01000",
        //         "cost":"45.6432",
        //         "fee":"0.223651680000000000",
        //         "order":"c9cac6a0-484c-4892-88e7-ad51b39f2ce1",
        //         "timestamp":1635921580399,
        //         "makerBuyer":false
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object type = null;
        Object timestamp = this.safeInteger(trade, "timestamp");
        Object priceString = this.safeString(trade, "price");
        Object amountString = this.safeString(trade, "quantity");
        Object costString = this.safeString(trade, "cost");
        Object makerBuyer = this.safeValue(trade, "makerBuyer");
        Object side = this.safeString(trade, "direction");
        if (Helpers.isTrue(Helpers.isEqual(side, null)))
        {
            side = ((Helpers.isTrue(makerBuyer))) ? "sell" : "buy";
        } else
        {
            if (Helpers.isTrue(Helpers.isEqual(side, "TRADE_DIRECTION_BUY")))
            {
                side = "buy";
            } else if (Helpers.isTrue(Helpers.isEqual(side, "TRADE_DIRECTION_SELL")))
            {
                side = "sell";
            }
        }
        Object isBuy = (Helpers.isEqual(side, "buy"));
        Object takerOrMaker = ((Helpers.isTrue((Helpers.isTrue(makerBuyer) && Helpers.isTrue(isBuy))))) ? "maker" : "taker";
        Object baseId = this.safeString(trade, "baseCurrency");
        Object quoteId = this.safeString(trade, "quoteCurrency");
        Object base = this.safeCurrencyCode(baseId);
        Object quote = this.safeCurrencyCode(quoteId);
        Object symbol = Helpers.add(Helpers.add(base, "/"), quote);
        if (Helpers.isTrue(Helpers.inOp(this.markets, symbol)))
        {
            market = this.market(symbol);
        }
        Object id = this.safeString(trade, "id");
        Object orderId = this.safeString(trade, "order");
        Object feeCost = this.safeString(trade, "fee");
        Object fee = null;
        if (Helpers.isTrue(!Helpers.isEqual(feeCost, null)))
        {
            final Object finalFeeCost = feeCost;
            fee = new java.util.HashMap<String, Object>() {{
                put( "cost", finalFeeCost );
                put( "currency", quote );
            }};
        }
        final Object finalSymbol = symbol;
        final Object finalSide = side;
        final Object finalFee = fee;
        return this.safeTrade(new java.util.HashMap<String, Object>() {{
            put( "info", trade );
            put( "timestamp", timestamp );
            put( "datetime", LatokenCore.this.iso8601(timestamp) );
            put( "symbol", finalSymbol );
            put( "id", id );
            put( "order", orderId );
            put( "type", type );
            put( "takerOrMaker", takerOrMaker );
            put( "side", finalSide );
            put( "price", priceString );
            put( "amount", amountString );
            put( "cost", costString );
            put( "fee", finalFee );
        }}, market);
    }

