    /**
     * @method
     * @name latoken#createOrder
     * @description create a trade order
     * @see https://api.latoken.com/doc/v2/#tag/Order/operation/placeOrder
     * @see https://api.latoken.com/doc/v2/#tag/StopOrder/operation/placeStopOrder  // stop
     * @param {string} symbol unified symbol of the market to create an order in
     * @param {string} type 'market' or 'limit'
     * @param {string} side 'buy' or 'sell'
     * @param {float} amount how much of currency you want to trade in units of base currency
     * @param {float} [price] the price at which the order is to be fulfilled, in units of the quote currency, ignored in market orders
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {float} [params.triggerPrice] the price at which a trigger order is triggered at
     *
     * EXCHANGE SPECIFIC PARAMETERS
     * @param {string} [params.condition] "GTC", "IOC", or  "FOK"
     * @param {string} [params.clientOrderId] [ 0 .. 50 ] characters, client's custom order id (free field for your convenience)
     * @returns {object} an [order structure]{@link https://docs.ccxt.com/?id=order-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> createOrder(Object symbol, Object type, Object side, Object amount, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object price = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object market = this.market(symbol);
            Object uppercaseType = ((String)type).toUpperCase();
            final Object finalUppercaseType = uppercaseType;
            Object request = new java.util.HashMap<String, Object>() {{
                put( "baseCurrency", Helpers.GetValue(market, "baseId") );
                put( "quoteCurrency", Helpers.GetValue(market, "quoteId") );
                put( "side", ((String)side).toUpperCase() );
                put( "condition", "GTC" );
                put( "type", finalUppercaseType );
                put( "clientOrderId", LatokenCore.this.uuid() );
                put( "quantity", LatokenCore.this.amountToPrecision(symbol, amount) );
                put( "timestamp", LatokenCore.this.seconds() );
            }};
            if (Helpers.isTrue(Helpers.isEqual(uppercaseType, "LIMIT")))
            {
                Helpers.addElementToObject(request, "price", this.priceToPrecision(symbol, price));
            }
            Object triggerPrice = this.safeString2(parameters, "triggerPrice", "stopPrice");
            parameters = this.omit(parameters, new java.util.ArrayList<Object>(java.util.Arrays.asList("triggerPrice", "stopPrice")));
            Object response = null;
            if (Helpers.isTrue(!Helpers.isEqual(triggerPrice, null)))
            {
                Helpers.addElementToObject(request, "stopPrice", this.priceToPrecision(symbol, triggerPrice));
                response = (this.privatePostAuthStopOrderPlace(this.extend(request, parameters))).join();
            } else
            {
                response = (this.privatePostAuthOrderPlace(this.extend(request, parameters))).join();
            }
            //
            //    {
            //        "baseCurrency": "f7dac554-8139-4ff6-841f-0e586a5984a0",
            //        "quoteCurrency": "a5a7a7a9-e2a3-43f9-8754-29a02f6b709b",
            //        "side": "BID",
            //        "clientOrderId": "my-wonderful-order-number-71566",
            //        "price": "10103.19",
            //        "stopPrice": "10103.19",
            //        "quantity": "3.21",
            //        "timestamp": 1568185507
            //    }
            //
            return this.parseOrder(response, market);
        });

    }

